// // This comment is misleading because it suggests the ADC extends the 12-bit input to 16 bits by truncating the upper 4 bits, which is the opposite of what the code actually does.
module adc_simulator(
    input [11:0] analog_input,
    output [15:0] digital_output
);  
    assign digital_output = {4'b0000, analog_input};  
endmodule
